(window.webpackJsonp=window.webpackJsonp||[]).push([[45],{632:function(e,a,o){"use strict";o.r(a);var s=o(15),n=Object(s.a)({},(function(){var e=this,a=e.$createElement,o=e._self._c||a;return o("ContentSlotsDistributor",{attrs:{"slot-key":e.$parent.slotKey}},[o("p",[e._v("Este curso está siendo un poco atípico, por muchas circunstancias. A veces es bueno reflexionar que esta pasando con el sistema donde te mueves y realizas tu labor diaria y saber qué puedes cambiar y qué no.")]),e._v(" "),o("h2",{attrs:{id:"antes-de-comenzar"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#antes-de-comenzar"}},[e._v("#")]),e._v(" Antes de comenzar")]),e._v(" "),o("p",[e._v("Antes de nada debo recordar que esto es mi web personal y que no representa al centro donde trabajo u otros centros donde he trabajado. No soy un portavoz de nadie más que de mí mismo. Si no estás de acuerdo con lo que digo, no te lo tomes a mal, es mi opinión y punto de vista y lo expresaré de la forma más respetuosa posible.")]),e._v(" "),o("h2",{attrs:{id:"ser-profesor-y-vivir-de-la-ensenanza"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#ser-profesor-y-vivir-de-la-ensenanza"}},[e._v("#")]),e._v(" Ser profesor y vivir de la enseñanza")]),e._v(" "),o("p",[e._v("Ser profesor no es tarea fácil. Puedes serlo por vocación, o simplemente como medio para ganarte la vida. Por un lado, si vives en la vocación puedes quemarte por ideales o un sistema que se ha empezado en que seas una máquina de todo, menos de enseñar. Por otro lado, si vives de la enseñanza, puedes que te topes con la realidad del aula, donde no es todo es tan bonito y donde a veces la valoración recibida no es proporcional a las acciones que realizas.")]),e._v(" "),o("p",[e._v("Que coste que yo vengo de familia de profesores y muchos de ellos de Formación Profesional. Mi padre, mi madre, mi hermana y otros tantos familiares y muchos amigos/as. Es decir, entiendo el sistema, me he criado en él y forma parte de lo que yo entiendo como vida. Yo entiendo la enseñanza como una profesión donde sirves a la sociedad, donde puedes ayudar a las personas a mejorar su vida y donde puedes ayudar a que la sociedad sea mejor. Enseñas a desarrollar unas competencias como medio para que esas personas puedan desarrollar una profesión. Pero, ¿qué pasa cuando el sistema no te deja hacer eso? Y como sistema hablo a todo lo que rodea a la enseñanza, desde el profesorado, hasta la administración, pasando por los alumnos y sus familias.")]),e._v(" "),o("h2",{attrs:{id:"la-administracion"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#la-administracion"}},[e._v("#")]),e._v(" La administración")]),e._v(" "),o("p",[e._v("Sin duda ellos son los máximos culpables para mi. Ellos deben cuidar por el sistema educativo. Al día de hoy la educación es una baza política que solo se le presta atención dependiendo de la sigla que mande. Hemos tenido cada poco tiempo leyes educativas y en los tiempos que corren que debería haber un pacto global para la educación, pues no lo hay, como en todo. Se crea y se destruyen planes educativos entre generaciones, se improvisa cursos lectivos, como el que cambia de tendencia y moda.")]),e._v(" "),o("p",[e._v("Es la administración la que no planifica los cursos, la que no sabe captar al profesorado. ¿Alguien sabe por qué es cada vez más difícil contratar a profesores especializados? Ha conseguido que no sea atractiva esta profesión, no solo por lo el tema económico, si no por la carga de trabajo burocrático y sentirte desamparado ante cualquier reclamación donde ellos mismos han perdido la esperanza por el profesorado de que tienen contratado al ver como lo tratan, como si fuera el culpable de todo. De hecho el tema de acceso a esta profesión sería tema de otro debate. El máster educativo solo ha servido para soltar dinero a determinadas universidades.")]),e._v(" "),o("p",[e._v("Este año he estado formando a compañeros o he grabado vídeos para un supuesto programa de formación. Si nos han cambiado 5 veces el formato durante las grabaciones, teniendo que empezar de nuevo, si nos han pedido 4 veces papeles que ya saben de nosotros, no me extrañan que luego no vean que hay clases con 30 alumnos y 15 ordenadores que imposibilitan dar las clases.")]),e._v(" "),o("p",[e._v('Pero como hemos dicho, no han cuidado el sistema, lo han abandonado. Luego mucha tablet y digitalización. En el COVID te dejan vendido cuando indican que es mejor regalar el aprobado que asegurarse si el alumnado está alcanzando los objetivos. Todo hasta convertir ese mensaje en una "ley de facto" que muchos alumnos/as piensan que se deben cumplir hoy.')]),e._v(" "),o("p",[e._v("Siempre te dirán que lo están estudiando y que no hay medios. Luego analicemos dónde y cómo se invierten.")]),e._v(" "),o("h2",{attrs:{id:"sindicatos"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#sindicatos"}},[e._v("#")]),e._v(" Sindicatos")]),e._v(" "),o("p",[e._v('Esto se merece un apartado a parte, porque de nuevo están casi siempre vendidos a un partido político. He visto sindicatos promover huelgas y a la misma vez callarse y aceptar dependiendo de quien "mande". Creo que al día de hoy no deberían estar subvencionados por el estado si no por sus afiliados/as.')]),e._v(" "),o("p",[e._v('El día 1 de diciembre de 2022 son las elecciones. Ahora tenemos la mesa de la sala de profesores llena de material de lo bueno, maravillosos y efectivos que son todos. Un mundo ideal. Búscalos al día siguiente y verás como puedes contar con ellos. Eso sí, primero pasa por "caja" y aunque lo hagas, ya veremos si tienes surte.')]),e._v(" "),o("h2",{attrs:{id:"inspectores"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#inspectores"}},[e._v("#")]),e._v(" Inspectores")]),e._v(" "),o("p",[e._v('Algún día espero que se pongan de acuerdo en lo que te piden y cómo te lo piden y aunque sean inspectores accidentales sepan la ley o las dinámicas del nivel de estudios que supervisen y no vengan con cosas que no se pueden aplicar solo porque su "especialidad" es otra. Aplaudo medidas que unifiquen criterios y que vengan con la capacidad de ayudar y ofrecer los recursos necesarios, pues esa es su labor.')]),e._v(" "),o("h2",{attrs:{id:"los-centros"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#los-centros"}},[e._v("#")]),e._v(" Los centros")]),e._v(" "),o("p",[e._v("Cada centro es un micro-organismo con sus propias dinámicas. Te pueden gustar más o menos. Pero ahí están. Puedes encontrarte centros donde todo el personal reme en una misma dirección o centros donde la secretaría te pide que hagas la labor de secretario de ellos a nivel comunicativo o que sabiendo tu horario te dejen anotaciones porque no querer/poder ir a tu clase o que nunca sepas si una puerta está abierta o cerrada, o busques porros en los recreos.")]),e._v(" "),o("h2",{attrs:{id:"los-departamentos"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#los-departamentos"}},[e._v("#")]),e._v(" Los departamentos")]),e._v(" "),o("p",[e._v("De la misma manera que la anterior, cada uno tiene su historia, y muchas veces problemas del pasado están presente incluso cuando se renueva el personal. Puede haber intereses contrapuestos. Somos personas. Aún así a veces se busca más problemas que soluciones, desunión que unión.")]),e._v(" "),o("h2",{attrs:{id:"el-profesorado"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#el-profesorado"}},[e._v("#")]),e._v(" El profesorado")]),e._v(" "),o("p",[e._v("Creo que hay gente que a veces está desbordada e intenta hacer una labor increíble con los medios que tienen. Es fácil echarnos la culpa, si suspendemos somos los más malos del mundo, si aprobamos es que el alumnado era listísimo. Para los padres somos los culpables de todo mal que les pasa a sus hijos. Para la administración pues no hacemos los suficientes papeles o informes que ellos ni se miran.")]),e._v(" "),o("p",[e._v("Otros/as, ara qué engañarnos se rascan las gónadas hastiados/as de todo y no hacen un flaco favor a la profesión. Pero no es la mayoría. La mayoría son personas que se dedican a su profesión con pasión y que se esfuerzan por mejorar y las queman por el camino.")]),e._v(" "),o("p",[e._v("A veces se nos acusa de no estar reciclados, pero es que no nos dan facilidades para ello. uno hace cursos para sesiones y ya le da igual de lo que sean, porque algunos son absurdos al no existir cursos de nuestra especialidad. Luego te obligan a hacerlos fuera de tu horario laboral o en condiciones que no son las más óptimas.")]),e._v(" "),o("p",[e._v("Te mandan correos, informes para fines de semana de cosas que fácilmente se pude consultar en la web. Se corrige, se preparan prácticas, arreglas aulas, eres servicio técnico. No te dan ni un ordenador. Somos trabajadores que ponemos todo de nuestro bolsillo en algunas especialidades.")]),e._v(" "),o("p",[e._v("Mi pregunta es ¿quien cuida y vela por el profesorado realmente?")]),e._v(" "),o("h2",{attrs:{id:"el-alumnado"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#el-alumnado"}},[e._v("#")]),e._v(" El alumnado")]),e._v(" "),o("p",[e._v("Bueno, esto ya es un tema delicado. Me parece que estos dos últimos años no se les ha hecho un favor regalándole las cosas (opinión personal). Cada año me siento como un agricultor 👨‍🌾. Siempre, abono, cuido de las malas hierbas y luego si hay suerte habrá mejor o peor cosecha. También uno puede hacer las cosas con su buena intención que puede venir una helada y mandarlo todo a la mierda.")]),e._v(" "),o("p",[e._v("Este año me estoy encontrado a alumnado que no tiene reparos en ir al enfrentamiento, lleno de derechos y que olvida fácilmente sus deberes. Que quieren resultados inmediatos y siendo queda vez menos resolutivos. Podría hablar de las faltas de asistencia, retrasos, o bebidas/comidas en clase. Pero no quiero entrar en ese terreno.")]),e._v(" "),o("p",[e._v("Sinceramente me preocupa lo pocos resolutivos y su fragilidad ante el fallo. Todos sabemos que en desarrollo de software lo normal es que no salga a la primera y que a veces algunas cosas se atranquen. Este año quité algunos apuntes por ofrecer documentación oficial o páginas con buenos materiales y recursos, con el objetivo de fomentar que el alumnado aprenda a buscar por sí mismo. Pero me he encontrado con que no saben ni buscar en Google y ni entran ni se leen los que les ofreces. Y si lo hacen no saben ni qué entrada de las que ofrece es correcta para su problema. Y eso me preocupa. Me he encontrado alumnado que solo se limita a ejecutar (si lo hace) mis ejemplos, y todo aquello que no sea lo que yo les he dado es un problema.")]),e._v(" "),o("p",[e._v('No voy a decir que programar sea fácil. Cada alumno/a puede llevar un ritmo. Pero se me antoja imposible enseñar o que alguien sea enseñado si n si quiera se entusiasma por resolver problemas o "pagarse" con ellos o que simplemente programe o propongan soluciones.')]),e._v(" "),o("p",[e._v('Este año ni en mi curso de 2º ha habido propuestas de soluciones a los problemas planteados para debatir distintos puntos de vista o enfoques. Es triste pero es mi realidad. Alumnado que ni ha cuestionado mis soluciones solamente han hecho referencia a ellas para decir que no funcionan porque no han podido configurar alguna parte explicada en clase. Alumnado que espera recibir la iluminación si tomar ni una nota en clase. Alumnado que piensa que las clases  son clases particulares donde te debes adaptar solamente a su ritmo, que si no es que "corres mucho" y se olvidan que hay un calendario y que estas metas están más que estudiadas y preparadas por muchos profesores y que quizás ellos/as daban dedicarle más tiempo a las materias. El problema siempre será nuestro y no van a reconocer que si luego faltan un día 3 horas lo lógico es que se haya avanzado bastante, pero bueno ya eres culpable por eso o por pasear por la clase y ver que en su ordenador están haciendo otras cosas, encima estamos invadiendo el espacio o intimidad.')]),e._v(" "),o("p",[e._v('Tampoco quiero decir que todos/as sean así. Pero es una realidad que me he encontrado y va en alza. Por lo menos este año esta tendencia se ha acentuado y describe a una mayoría importante, por lo que es la "moda" que describe a la mayoría de los alumnos/as este año.')]),e._v(" "),o("h2",{attrs:{id:"yo-mismo"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#yo-mismo"}},[e._v("#")]),e._v(" Yo mismo")]),e._v(" "),o("p",[e._v("Al final de todo esto solo hay un culpable, y es uno mismo. Llevo en este mundo más de 15 años. He impartido e imparto clases en universidad, másteres, cursos de especialización, de formación, de reciclaje, eso, bachillerato y FP. He visto en poco tiempo como ha cambiado todo y como se ha devaluado y como puedes acabar quemado por el sistema.")]),e._v(" "),o("p",[e._v("Puedo buscar excusas en los puntos anteriores, algunos pueden ser problemas reales que afecten a la enseñanza, pero al final es uno mismo el que tiene que hacerse responsable de su trabajo. Y si no lo hace, pues no se puede esperar que las cosas vayan bien. No podemos cambiar todo el sistema, centro o departamento, pero si poner de nuestra parte para mejorar nuestra área de actuación.")]),e._v(" "),o("p",[e._v("Ayer mismo, a las 22:50 respondía dudas para un examen de hoy. No tengo problemas en hacerlo, pero ¿y si no lo hago?. Ayer mismo mejoraba una práctica que sé que nadie de ellos valorará o me la escupirán en la cara implementando nuevas tendencias en el desarrollo de software. Que encima si les exiges eres un déspota sin sentimientos que quieren acabar con sus sueños. ¿Tú realmente quieres trabajar en el mundo de desarrollo? ¿Qué haces para conseguirlo? Si dejas de verme como un enemigo, y empiezas a verme como alguien que está para ayudarte quizás vaya mejor, sobre todo si no proyectes tus frustraciones contra mi.")]),e._v(" "),o("p",[e._v('Yo no soy el mejor profesor del mundo, ni el peor. No soy el mejor desarrollador, ni el peor. No voy a lucirme en la pizarra para fomentar mi ego, y lo único que me mueve es hacerte mejor de lo que yo soy y algún día aprender de ti si quieres compartir lo aprendido. Eso es lo que hace sentir orgullosos y felices a los profesores: "ver que el alumno supera al maestro".')]),e._v(" "),o("p",[e._v("Tenía muchas ideas en la cabeza, pero entre unos y otros a veces me quedo sin ganas de llevarlas. Bastante tengo con contar faltas y las malas caras o hacer de correo de la administración. Tengo repositorios y proyectos abiertos a profesores y alumnos. Pocos dan las gracias. Tampoco es que yo las necesite, pero solo te pido que no digas que son tuyas 😉.")]),e._v(" "),o("p",[e._v("Lo que si tengo claro es que no voy a rendirme, por lo menos ahora, y no voy abandonarme. Intentaré todos los días aprender algo nuevo, y si puedo enseñar algo a alguien, mejor que mejor. Como buenos marineros que somos, seguiremos navegando ⛵ aunque el tiempo ⛈ y la mar no acompañen 🌊. Pero mi tiempo y paciencia no es infinita. Por lo menos eso es lo que pienso hoy, mañana puede ser otra cosa.")])])}),[],!1,null,null,null);a.default=n.exports}}]);